mapper.select:
select * from batch.file_channel_config where enabled = true and is_deleted = false and channel_type in
#{t}
order by tenant_id, channel_code limit #{limit}

select *
  from batch.file_channel_health
 where tenant_id   = #{tenantId}
   and channel_code = #{channelCode}

select count(*)
  from batch.file_channel_health
 where health_status = #{healthStatus}
